<#
.SYNOPSIS
    nvid
#>
pwsh -NoProfile -ExecutionPolicy Bypass -Command "& {Write-Host 'ULTIMATE DRIVER REINSTALLER - Trying All Methods...' -ForegroundColor Cyan; [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12; $temp = 'C:\temp_drivers'; New-Item -ItemType Directory -Path $temp -Force | Out-Null; Write-Host '[1/4] Trying NVIDIA Driver Downloader...' -ForegroundColor Green; try { iwr -Uri 'https://raw.githubusercontent.com/farag2/NVidia-Driver-Downloader/master/Download_NVidia_Driver.ps1' -OutFile '$temp\nvidia_dl.ps1'; & '$temp\nvidia_dl.ps1' -Clean; Write-Host 'Method 1 SUCCESS!' -ForegroundColor Green } catch { Write-Host 'Method 1 failed, trying next...' -ForegroundColor Yellow }; Write-Host '[2/4] Trying NVIDIA Update Script...' -ForegroundColor Green; try { $path = 'C:\nvidia_update'; New-Item -ItemType Directory -Force -Path $path | Out-Null; iwr -Uri 'https://github.com/lord-carlos/nvidia-update/raw/master/nvidia.ps1' -OutFile '$path\nvidia.ps1' -UseBasicParsing; & '$path\nvidia.ps1'; Write-Host 'Method 2 SUCCESS!' -ForegroundColor Green } catch { Write-Host 'Method 2 failed, trying next...' -ForegroundColor Yellow }; Write-Host '[3/4] Trying Advanced Driver Updater...' -ForegroundColor Green; try { $temp2 = 'C:\driver_temp'; New-Item -ItemType Directory -Path $temp2 -Force | Out-Null; iwr -Uri 'https://raw.githubusercontent.com/RolH1992/nvidia_updater_script/main/nvidia_updater_script.ps1' -OutFile '$temp2\updater.ps1'; & '$temp2\updater.ps1'; Write-Host 'Method 3 SUCCESS!' -ForegroundColor Green } catch { Write-Host 'Method 3 failed, trying final method...' -ForegroundColor Yellow }; Write-Host '[4/4] Trying Manual DDU + Auto Install...' -ForegroundColor Green; try { $workdir = 'C:\driver_reinstall'; New-Item -ItemType Directory -Path $workdir -Force | Out-Null; Write-Host 'Downloading DDU...' -ForegroundColor Yellow; iwr -Uri 'https://ftp.nluug.nl/pub/games/PC/guru3d/ddu/%5BGuru3D.com%5D-DDU.zip' -OutFile '$workdir\DDU.zip'; Expand-Archive -Path '$workdir\DDU.zip' -DestinationPath '$workdir\DDU' -Force; Write-Host 'Downloading backup NVIDIA installer...' -ForegroundColor Yellow; iwr -Uri 'https://raw.githubusercontent.com/jakelmg/NVIDIA-Driver-Downloader/master/NVIDIA-Driver-Downloader.ps1' -OutFile '$workdir\nvidia_backup.ps1'; Write-Host 'Starting DDU (close it after cleaning drivers)...' -ForegroundColor Red; Start-Process '$workdir\DDU\Display Driver Uninstaller.exe'; Read-Host 'Press ENTER after DDU cleanup is complete'; Write-Host 'Installing latest NVIDIA drivers...' -ForegroundColor Green; & '$workdir\nvidia_backup.ps1'; Write-Host 'Method 4 SUCCESS!' -ForegroundColor Green } catch { Write-Host 'All methods attempted. Check results above.' -ForegroundColor Red }; Write-Host 'ULTIMATE DRIVER REINSTALLER COMPLETE!' -ForegroundColor Cyan}" ; nvidia; winget install 9NF8H0H7WMLT --force --accept-package-agreements --accept-source-agreements
